#include <stdio.h>

typedef enum { INTEGER_VALUE, DOUBLE_VALUE } ValueTag;
typedef struct { ValueTag tag; union { long long integer; double decimal; } data; } Value;

int main(void) {
    char tag;
    if (scanf(" %c", &tag) != 1) return 1;
    Value value;
    if (tag == 'i') { value.tag = INTEGER_VALUE; if (scanf("%lld", &value.data.integer) != 1) return 1; }
    else if (tag == 'd') { value.tag = DOUBLE_VALUE; if (scanf("%lf", &value.data.decimal) != 1) return 1; }
    else { puts("invalid"); return 0; }
    if (value.tag == INTEGER_VALUE) printf("int %lld\n", value.data.integer);
    else printf("double %.2f\n", value.data.decimal);
    return 0;
}
